function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    lines = [];
    for (let i = 0; i < 5; i++) {
        lines.push({
            y: Math.random() * h,
            length: Math.random() * 200 + 150,
            speed: Math.random() * 0.5 + 0.2,
            opacity: Math.random() * 0.3 + 0.1
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);
    ctx.lineWidth = 1.5;
    for (let l of lines) {
        l.y += Math.sin(l.y * 0.01) * 0.1; // Gentle sway
        ctx.strokeStyle = `rgba(255, 255, 255, ${l.opacity})`;
        ctx.beginPath();
        ctx.moveTo(0, l.y);
        ctx.quadraticCurveTo(w / 2, l.y + 40, w, l.y);
        ctx.stroke();
    }
    requestAnimationFrame(render);
}

oled.canvasScript:
/**
 * Title: Starfield Warp (Cosmic Horizon)
 * Description: Classic 2D warp-speed star travel.
 */
let canvas, ctx, w, h;
let stars = [];

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    stars = [];
    for (let i = 0; i < 100; i++) {
        stars.push({
            x: Math.random() * w - w/2,
            y: Math.random() * h - h/2,
            z: Math.random() * w
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.fillStyle = 'rgba(0, 0, 0, 0.25)';
    ctx.fillRect(0, 0, w, h);

    ctx.fillStyle = '#ffffff';
    for (let s of stars) {
        s.z -= 1.5;
        if (s.z <= 0) s.z = w;
        let px = (s.x / s.z) * (w / 2) + w/2;
        let py = (s.y / s.z) * (h / 2) + h/2;
        if (px < 0 || px > w || py < 0 || py > h) s.z = w;
        let size = (1 - s.z / w) * 3;
        ctx.fillRect(px, py, size, size);
    }
    requestAnimationFrame(render);
}

