            let y = (h * 0.4) 
                  + Math.sin(x * 0.002 + timeOffset) * CONFIG.baseAmplitude 
                  + Math.sin(x * 0.005 - timeOffset * 1.5) * (CONFIG.baseAmplitude * 0.5)
                  + Math.sin(x * 0.01 + timeOffset * 2) * (CONFIG.baseAmplitude * 0.2);
            let dx = mouse.x - x; let dy = mouse.y - y; let dist = Math.hypot(dx, dy);
            if (dist < 400) { let force = (400 - dist) / 400; y += force * force * (3 - 2 * force) * CONFIG.mouseDip; }
            ctx.lineTo(x, y);
        }
        ctx.lineTo(w, h);
        ctx.closePath();
        let grad = ctx.createLinearGradient(0, 0, w, h);
        grad.addColorStop(0, CONFIG.colorStart);
        grad.addColorStop(1, CONFIG.colorEnd);
        ctx.fillStyle = grad;
        ctx.fill();
    }
    requestAnimationFrame(render);
}

