dark.canvasScript:
let canvas, ctx, W, H;
const COLS = [];
const CHARS = '01アイウエオカキクケコサシスセソ><{}[]';
const FONT_SIZE = 14;
let colCount = 0;

function init(c, w, h) {
  canvas = c; ctx = c.getContext('2d'); W = w; H = h;
  colCount = Math.floor(W / FONT_SIZE);
  COLS.length = 0;
  for (let i = 0; i < colCount; i++) COLS.push(Math.random() * H / FONT_SIZE | 0);
}

function draw() {
  ctx.fillStyle = 'rgba(10, 0, 20, 0.08)';
  ctx.fillRect(0, 0, W, H);
