    if (a.y < 0 || a.y > H) a.dy *= -1;
    const glow = 0.5 + 0.5 * Math.sin(a.pulse);
    for (let j = i + 1; j < particles.length; j++) {
      const b = particles[j];
      const dx = a.x - b.x, dy = a.y - b.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < CONNECT_DIST) {
        ctx.beginPath();
        ctx.moveTo(a.x, a.y);
        ctx.lineTo(b.x, b.y);
        ctx.strokeStyle = '#d4a0c0';
        ctx.globalAlpha = (1 - dist / CONNECT_DIST) * 0.15;
        ctx.stroke();
        ctx.globalAlpha = 1;
      }
    }
    ctx.beginPath();
    ctx.arc(a.x, a.y, a.r + glow, 0, 6.283);
    ctx.fillStyle = a.color;
    ctx.globalAlpha = a.alpha * (0.7 + glow * 0.3);
    ctx.fill();
    ctx.globalAlpha = 1;
  }
  requestAnimationFrame(draw);
}

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

self.onmessage = function(e) {
  const { type, canvas: c, width, height, x, y } = e.data;
  switch (type) {
    case 'init': init(c, width, height); draw(); break;
    case 'resize': W = width; H = height; if (canvas) { canvas.width = W; canvas.height = H; } break;
    case 'mousemove': mouseX = x; mouseY = y; break;
  }
};

