/**
 * Title: Prismatic Caustics
 * Description: Shifting light patterns simulating refraction through glass.
 */

const CONFIG = {
    blobCount: 4,
    speed: 0.005,
    colors: [
        'rgba(100, 150, 255, 0.08)', 
        'rgba(200, 100, 255, 0.05)', 
        'rgba(255, 255, 255, 0.03)',
        'rgba(50, 200, 255, 0.06)'
    ]
};

let canvas, ctx, w, h;
let blobs = [];

setInterval(() => self.postMessage({ type: 'heartbeat' }), 1000);

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    blobs = [];
    for (let i = 0; i < CONFIG.blobCount; i++) {
        blobs.push({
            x: Math.random() * w, y: Math.random() * h,
            r: Math.random() * 500 + 400,
            vx: (Math.random() - 0.5) * 2,
            vy: (Math.random() - 0.5) * 2,
            color: CONFIG.colors[i % CONFIG.colors.length]
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);

    // Use screen blending to create soft prismatic overlays
    ctx.globalCompositeOperation = 'screen';

    for (let b of blobs) {
        b.x += b.vx; b.y += b.vy;
        if (b.x < -b.r) b.x = w + b.r; if (b.x > w + b.r) b.x = -b.r;
        if (b.y < -b.r) b.y = h + b.r; if (b.y > h + b.r) b.y = -b.r;

        let grad = ctx.createRadialGradient(b.x, b.y, 0, b.x, b.y, b.r);
        grad.addColorStop(0, b.color);
        grad.addColorStop(1, 'rgba(0,0,0,0)');

        ctx.fillStyle = grad;
        ctx.beginPath();
        ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
        ctx.fill();
    }

    requestAnimationFrame(render);
}

