dark.canvasScript:
/**
 * Title: Synthwave Perspective Grid
 * Description: A retro 80s 3D grid moving infinitely towards the horizon.
 */

const CONFIG = {
    speed: 0.04,
    spacing: 50,
    perspective: 350,
    horizonOffset: 0.45,  // 45% down the screen
    gridColor: 'rgba(255, 0, 255, 0.5)',   // Hot Pink
    horizonGlow: 'rgba(0, 255, 255, 0.8)'  // Cyan horizon line
};

let canvas, ctx, w, h;
let time = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

self.onmessage = (e) => {
    switch (e.data.type) {
        case 'init':
            canvas = e.data.canvas;
            ctx = canvas.getContext('2d');
            resize(e.data.width, e.data.height);
            render();
            break;
        case 'resize':
            resize(e.data.width, e.data.height);
            break;
    }
};

function resize(width, height) {
    w = width; 
    h = height;
    if (canvas) {
        canvas.width = w;
        canvas.height = h;
    }
}

function render() {
    if (!ctx) return;

    // Mandatory Transparency Clear
    ctx.clearRect(0, 0, w, h);

    time += CONFIG.speed;
    let horizon = h * CONFIG.horizonOffset;

    // Draw Horizon Line Glow
    ctx.shadowBlur = 20;
    ctx.shadowColor = CONFIG.horizonGlow;
    ctx.strokeStyle = CONFIG.horizonGlow;
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.moveTo(0, horizon);
    ctx.lineTo(w, horizon);
    ctx.stroke();

    // Reset shadow for grid
    ctx.shadowBlur = 0;
    ctx.strokeStyle = CONFIG.gridColor;
    ctx.lineWidth = 1.5;

    // 1. Perspective Horizontal Lines
    ctx.beginPath();
    for (let z = 1; z < 30; z++) {
        let trueZ = (z - (time % 1));
        if (trueZ <= 0) continue;

        let y = horizon + (CONFIG.perspective / trueZ) * 12;
        // Fade out lines near the horizon
        let alpha = Math.min(1, (y - horizon) / 50);

        if (y > horizon && y < h) {
            ctx.moveTo(0, y);
            ctx.lineTo(w, y);
        }
    }
    ctx.stroke();

    // 2. Perspective Vertical Lines (Vanishing point at center horizon)
    ctx.beginPath();
    let centerX = w / 2;
    for (let i = -w * 2; i < w * 3; i += CONFIG.spacing) {
        ctx.moveTo(centerX, horizon);
        ctx.lineTo(i, h);
    }
    ctx.stroke();

    requestAnimationFrame(render);
}

