/**
 * Title: Vaporwave Daylight Grid
 * Description: A bright, sun-kissed outrun grid.
 */

const CONFIG = {
    speed: 0.04,
    spacing: 50,
    perspective: 350,
    horizonOffset: 0.45,
    gridColor: 'rgba(255, 94, 0, 0.4)',     // Sunset Orange
    horizonGlow: 'rgba(153, 0, 204, 0.6)'  // Deep Purple horizon
};

let canvas, ctx, w, h;
let time = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

self.onmessage = (e) => {
    switch (e.data.type) {
        case 'init':
            canvas = e.data.canvas;
            ctx = canvas.getContext('2d');
            resize(e.data.width, e.data.height);
            render();
            break;
        case 'resize':
            resize(e.data.width, e.data.height);
            break;
    }
};

function resize(width, height) {
    w = width; 
    h = height;
    if (canvas) {
        canvas.width = w;
        canvas.height = h;
    }
}

function render() {
    if (!ctx) return;

    ctx.clearRect(0, 0, w, h);

    time += CONFIG.speed;
    let horizon = h * CONFIG.horizonOffset;

    ctx.strokeStyle = CONFIG.horizonGlow;
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.moveTo(0, horizon);
    ctx.lineTo(w, horizon);
    ctx.stroke();

    ctx.strokeStyle = CONFIG.gridColor;
    ctx.lineWidth = 1.5;

    ctx.beginPath();
    for (let z = 1; z < 30; z++) {
        let trueZ = (z - (time % 1));
        if (trueZ <= 0) continue;

        let y = horizon + (CONFIG.perspective / trueZ) * 12;

        if (y > horizon && y < h) {
            ctx.moveTo(0, y);
            ctx.lineTo(w, y);
        }
    }
    ctx.stroke();

    ctx.beginPath();
    let centerX = w / 2;
    for (let i = -w * 2; i < w * 3; i += CONFIG.spacing) {
        ctx.moveTo(centerX, horizon);
        ctx.lineTo(i, h);
    }
    ctx.stroke();

    requestAnimationFrame(render);
}

